import type { NavSection } from '@linm-soft/common-components';
import type { DevModuleGroup } from '../dev/types';

/** Map `devRoutes.ts` groups → Sidebar sections (standalone mock nav). */
export function devModulesToNavSections(modules: DevModuleGroup[]): NavSection[] {
  return modules.map((mod) => ({
    title: mod.title,
    items: mod.routes.map((r, idx) => ({
      id: `${mod.prefix.replace(/\//g, '')}-${idx}`,
      label: r.label,
      icon: mod.iconClass,
      path: r.url,
    })),
  }));
}
